(window.webpackJsonp=window.webpackJsonp||[]).push([[347],{642:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{string}</span> <span class=\\"hljs-variable\\">s</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">pairs</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{string}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> smallestStringWithSwaps = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">s, pairs</span>) </span>{\\n  <span class=\\"hljs-keyword\\">if</span>(pairs.length===<span class=\\"hljs-number\\">0</span>)<span class=\\"hljs-keyword\\">return</span> s\\n  <span class=\\"hljs-keyword\\">let</span> used=<span class=\\"hljs-built_in\\">Array</span>(s.length).fill(<span class=\\"hljs-literal\\">false</span>)\\n  <span class=\\"hljs-keyword\\">let</span> uf=<span class=\\"hljs-built_in\\">Array</span>(s.length).fill().map(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">n,i</span>)=&gt;</span>i)\\n  <span class=\\"hljs-keyword\\">let</span> group=<span class=\\"hljs-built_in\\">Array</span>(s.length).fill().map(<span class=\\"hljs-function\\"><span class=\\"hljs-params\\">()</span>=&gt;</span><span class=\\"hljs-keyword\\">new</span> <span class=\\"hljs-built_in\\">Set</span>())\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">find</span>(<span class=\\"hljs-params\\">i</span>)</span>{\\n    <span class=\\"hljs-keyword\\">if</span>(i!==uf[i]){\\n      uf[i]=find(uf[i])\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> uf[i]\\n  }\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">union</span>(<span class=\\"hljs-params\\">a,b</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> i=find(a),\\n        j=find(b)\\n    <span class=\\"hljs-keyword\\">if</span>(i===j)<span class=\\"hljs-keyword\\">return</span>\\n    <span class=\\"hljs-keyword\\">if</span>(group[i].size&lt;group[j].size){\\n      uf[i]=j\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> n <span class=\\"hljs-keyword\\">of</span> group[i]){\\n        group[j].add(n)\\n      }\\n      group[j].add(a)\\n      group[j].add(b)\\n      <span class=\\"hljs-comment\\">// group[j]=group[j].concat(group[i])</span>\\n      <span class=\\"hljs-comment\\">// if(!group[j].includes(a))group[j].push(a)</span>\\n      <span class=\\"hljs-comment\\">// if(!group[j].includes(b))group[j].push(b)  </span>\\n      group[i]=<span class=\\"hljs-keyword\\">new</span> <span class=\\"hljs-built_in\\">Set</span>()\\n    }<span class=\\"hljs-keyword\\">else</span>{\\n      \\n      uf[j]=i\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> n <span class=\\"hljs-keyword\\">of</span> group[j]){\\n        group[i].add(n)\\n      }\\n      group[i].add(a)\\n      group[i].add(b)\\n      <span class=\\"hljs-comment\\">// group[i]=group[i].concat(group[j])</span>\\n      <span class=\\"hljs-comment\\">// if(!group[i].includes(a))group[i].push(a)</span>\\n      <span class=\\"hljs-comment\\">// if(!group[i].includes(b))group[i].push(b)  </span>\\n      group[j]=<span class=\\"hljs-keyword\\">new</span> <span class=\\"hljs-built_in\\">Set</span>()\\n    }\\n  }\\n  \\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> [v,w] <span class=\\"hljs-keyword\\">of</span> pairs){\\n    union(v,w)\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> res=[]\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;group.length;i++){\\n    res.push(group[i])\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> ans=[]\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;res.length;i++){\\n    <span class=\\"hljs-keyword\\">let</span> str=[]\\n    <span class=\\"hljs-keyword\\">let</span> idArr=[]\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> id <span class=\\"hljs-keyword\\">of</span> res[i]){\\n      str.push(s[id])\\n      idArr.push(id)\\n    }\\n    idArr.sort(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a,b</span>)=&gt;</span>a-b)\\n    str.sort()\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;str.length;j++){\\n      used[idArr[j]]=<span class=\\"hljs-literal\\">true</span>\\n      ans[idArr[j]]=str[j]\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;used.length;i++){\\n    <span class=\\"hljs-keyword\\">if</span>(!used[i]){\\n      ans[i]=s[i]\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> ans.join(<span class=\\"hljs-string\\">\'\'</span>)\\n};\\n</code></pre>\\n"],"titleSlug":"smallest-string-with-swaps","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u5b57\u7b26\u4e32&nbsp;<code>s</code>\uff0c\u4ee5\u53ca\u8be5\u5b57\u7b26\u4e32\u4e2d\u7684\u4e00\u4e9b\u300c\u7d22\u5f15\u5bf9\u300d\u6570\u7ec4&nbsp;<code>pairs</code>\uff0c\u5176\u4e2d&nbsp;<code>pairs[i] =&nbsp;[a, b]</code>&nbsp;\u8868\u793a\u5b57\u7b26\u4e32\u4e2d\u7684\u4e24\u4e2a\u7d22\u5f15\uff08\u7f16\u53f7\u4ece 0 \u5f00\u59cb\uff09\u3002</p>\\n\\n<p>\u4f60\u53ef\u4ee5 <strong>\u4efb\u610f\u591a\u6b21\u4ea4\u6362</strong> \u5728&nbsp;<code>pairs</code>&nbsp;\u4e2d\u4efb\u610f\u4e00\u5bf9\u7d22\u5f15\u5904\u7684\u5b57\u7b26\u3002</p>\\n\\n<p>\u8fd4\u56de\u5728\u7ecf\u8fc7\u82e5\u5e72\u6b21\u4ea4\u6362\u540e\uff0c<code>s</code>&nbsp;\u53ef\u4ee5\u53d8\u6210\u7684\u6309\u5b57\u5178\u5e8f\u6700\u5c0f\u7684\u5b57\u7b26\u4e32\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1:</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>s = &quot;dcab&quot;, pairs = [[0,3],[1,2]]\\n<strong>\u8f93\u51fa\uff1a</strong>&quot;bacd&quot;\\n<strong>\u89e3\u91ca\uff1a</strong> \\n\u4ea4\u6362 s[0] \u548c s[3], s = &quot;bcad&quot;\\n\u4ea4\u6362 s[1] \u548c s[2], s = &quot;bacd&quot;\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>s = &quot;dcab&quot;, pairs = [[0,3],[1,2],[0,2]]\\n<strong>\u8f93\u51fa\uff1a</strong>&quot;abcd&quot;\\n<strong>\u89e3\u91ca\uff1a</strong>\\n\u4ea4\u6362 s[0] \u548c s[3], s = &quot;bcad&quot;\\n\u4ea4\u6362 s[0] \u548c s[2], s = &quot;acbd&quot;\\n\u4ea4\u6362 s[1] \u548c s[2], s = &quot;abcd&quot;</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>s = &quot;cba&quot;, pairs = [[0,1],[1,2]]\\n<strong>\u8f93\u51fa\uff1a</strong>&quot;abc&quot;\\n<strong>\u89e3\u91ca\uff1a</strong>\\n\u4ea4\u6362 s[0] \u548c s[1], s = &quot;bca&quot;\\n\u4ea4\u6362 s[1] \u548c s[2], s = &quot;bac&quot;\\n\u4ea4\u6362 s[0] \u548c s[1], s = &quot;abc&quot;\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= s.length &lt;= 10^5</code></li>\\n\\t<li><code>0 &lt;= pairs.length &lt;= 10^5</code></li>\\n\\t<li><code>0 &lt;= pairs[i][0], pairs[i][1] &lt;&nbsp;s.length</code></li>\\n\\t<li><code>s</code>&nbsp;\u4e2d\u53ea\u542b\u6709\u5c0f\u5199\u82f1\u6587\u5b57\u6bcd</li>\\n</ul>\\n","title":"1202. \u4ea4\u6362\u5b57\u7b26\u4e32\u4e2d\u7684\u5143\u7d20","relatedTags":["\u5e76\u67e5\u96c6","\u6570\u7ec4"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1202"}')}}]);